def generate(history, round_num):
    # 6구간 균등 분산: 구간 겹침이 없어 항상 서로 다른 6개 보장.
    # 구간쏠림·범위 협소 회피용. 적중 확률 향상 주장 아님.
    bins = [(1, 7), (8, 15), (16, 23), (24, 31), (32, 38), (39, 45)]
    for _ in range(300):
        pick = sorted(random.randint(a, b) for a, b in bins)
        s = sum(pick)
        odd = sum(1 for x in pick if x % 2)
        consec = any(pick[i + 1] - pick[i] == 1 for i in range(5))
        if 100 <= s <= 170 and 2 <= odd <= 4 and not consec:
            return pick
    return sorted(random.sample(range(1, 46), 6))

