def generate(history, round_num):
    recent = past(history, round_num, 60)
    freq = Counter()
    for r in recent:
        for n in r["numbers"]:
            freq[n] += 1
    nums = list(range(1, 46))
    weights = [1.0 / (freq[n] + 1) for n in nums]
    for _ in range(400):
        pick = set()
        while len(pick) < 6:
            pick.add(random.choices(nums, weights=weights, k=1)[0])
        pick = sorted(pick)
        s = sum(pick)
        odd = sum(1 for n in pick if n % 2 == 1)
        low = sum(1 for n in pick if n <= 31)
        consec = any(pick[i+1] - pick[i] == 1 for i in range(5))
        if 100 <= s <= 170 and 2 <= odd <= 4 and low <= 4 and not consec:
            return pick
    return sorted(random.sample(nums, 6))
